div.div:
-- tags 关系表：精确匹配 + AND/OR 过滤


-- 由 indexer.index_file 在写 documents 后同步维护（delete-then-insert）


-- documents 行删除时 ON DELETE CASCADE 自动清


-- rebuild_fts 不触碰此表（tags 来自 frontmatter 原文，与分词器无关）


CREATE TABLE document_tags (


doc_rowid INTEGER NOT NULL REFERENCES documents(rowid) ON DELETE CASCADE,


tag TEXT NOT NULL,


PRIMARY KEY (doc_rowid, tag)


) WITHOUT ROWID;


CREATE INDEX idx_document_tags_tag ON document_tags(tag);
